// Idempotent seed for demo users per design-spec §4.2.
// Generates valid Thai-ID checksums on the fly.

import { auth, db } from "../lib/admin";

function buildId(stem12: string): string {
  if (stem12.length !== 12) throw new Error("stem must be 12 digits");
  const digits = stem12.split("").map((c) => Number.parseInt(c, 10));
  let sum = 0;
  for (let i = 0; i < 12; i++) sum += digits[i] * (13 - i);
  const check = (11 - (sum % 11)) % 10;
  return stem12 + check.toString();
}

interface DemoUser {
  uid: string;
  stem12: string;
  name: string;
  phone: string;
  password: string;
  lat: number;
  lng: number;
  label: string;
}

const USERS: DemoUser[] = [
  { uid: "user-mali",    stem12: "110000000010", name: "Mali Suwan",      phone: "+66810000101", password: "Demo#101", lat: 13.7563, lng: 100.5018, label: "Bangkok central shelter" },
  { uid: "user-naree",   stem12: "110000000010", name: "Naree Charoen",   phone: "+66810000102", password: "Demo#102", lat: 13.7460, lng: 100.5300, label: "East shelter" },
  { uid: "user-somchai", stem12: "110000000010", name: "Somchai T.",      phone: "+66810000103", password: "Demo#103", lat: 13.7700, lng: 100.5300, label: "North shelter" },
];

// All three stems collide intentionally so the script demonstrates how to
// pick distinct stems. Real Day-1 work: rotate stems per user.
const STEM_OFFSETS = ["110000000010", "110000000020", "110000000030"];

export async function seedDemoUsers(): Promise<void> {
  for (let i = 0; i < USERS.length; i++) {
    const u = USERS[i];
    const nationalId = buildId(STEM_OFFSETS[i]);
    const email = `${nationalId}@drone-aid.local`;

    try {
      await auth.getUser(u.uid);
    } catch {
      await auth.createUser({
        uid: u.uid,
        email,
        password: u.password,
        emailVerified: true,
        displayName: u.name,
        disabled: false,
      });
    }

    await db.doc(`users/${u.uid}`).set({
      nationalId,
      name: u.name,
      phone: u.phone,
      role: "user",
      locked: false,
      fcmTokens: [],
      deliveryAddress: { lat: u.lat, lng: u.lng, label: u.label },
    }, { merge: true });
  }
  console.log(`seedDemoUsers: ensured ${USERS.length} demo users.`);
}
// Idempotent seed for the demo admin (and a placeholder password).
// Per design-spec §4.1. Run once after firebase deploy.
//
// SECURITY: passwords here are obvious demo strings. Never use this script
// against a production project; the redactor catches IDs but not these
// passwords.

import { auth, db } from "../lib/admin";

interface SeedAdmin {
  uid: string;
  nationalId: string;
  name: string;
  email: string;
  password: string;
  phone: string;
}

const ADMINS: SeedAdmin[] = [
  {
    uid: "admin-aok",
    nationalId: "[REDACTED:thai-id]",
    name: "Aok Lead",
    email: "[REDACTED:thai-id]@drone-aid.local",
    password: "Admin#001",
    phone: "+66810000001",
  },
];

export async function seedAdmins(): Promise<void> {
  for (const a of ADMINS) {
    // Upsert Auth user.
    try {
      await auth.getUser(a.uid);
    } catch {
      await auth.createUser({
        uid: a.uid,
        email: a.email,
        emailVerified: true,
        password: a.password,
        displayName: a.name,
        disabled: false,
      });
    }

    // Upsert users doc with role=admin (overrides what onUserCreated wrote).
    await db.doc(`users/${a.uid}`).set({
      nationalId: a.nationalId,
      name: a.name,
      phone: a.phone,
      role: "admin",
      locked: false,
      fcmTokens: [],
      deliveryAddress: null,
    }, { merge: true });
  }
  console.log(`seedAdmins: ensured ${ADMINS.length} admin(s).`);
}

