1	// Auth trigger: provision users/{uid} on first sign-in.
2	// Spec: §5 auth/roles, §10 onUserCreated.
3	//
4	// The synthetic email format is `<nationalId>@drone-aid.local`. We extract
5	// the national ID from it. If a record already exists (e.g. seed script
6	// pre-created it), we merge instead of overwriting.
7	
8	import * as functions from "firebase-functions/v1";
9	import { db, FieldValue } from "../lib/admin";
10	
11	const EMAIL_SUFFIX = "@drone-aid.local";
12	
13	export const onUserCreated = functions
14	  .region("asia-southeast1")
15	  .auth.user()
16	  .onCreate(async (user) => {
17	    let nationalId: string | null = null;
18	    if (user.email && user.email.endsWith(EMAIL_SUFFIX)) {
19	      nationalId = user.email.slice(0, -EMAIL_SUFFIX.length);
20	    }
